options.afterRender:
const root = typeof document !== "undefined" ? document : null;
if (root) {
  root.querySelectorAll(".puda-bubble").forEach((bubble) => {
    const text = bubble.querySelector(".puda-bubble-text");
    const button = bubble.querySelector(".puda-show-more");
    if (!text || !button) return;
    const overflowing = text.scrollHeight > text.clientHeight + 2;
    bubble.classList.toggle("puda-overflowing", overflowing);
    button.onclick = () => {
      bubble.classList.toggle("puda-expanded");
      button.textContent = bubble.classList.contains("puda-expanded") ? "Show less" : "Show more";
    };
  });
}
